31	const cachedSet = new Set<Entity>();
32	const cachedQueue = [] as Entity[];
33	
34	export function destroyEntity(world: World, entity: Entity) {
35	    const ctx = world[$internal];
36	
37	    // Check if entity exists.
38	    if (!world.has(entity)) throw new Error('Koota: The entity being destroyed does not exist.');
39	
40	    // Caching the lookup in the outer scope of the loop increases performance.
41	    const entityQueue = cachedQueue;
42	    const processedEntities = cachedSet;
43	
44	    // Ensure the queue is empty before starting.
45	    entityQueue.length = 0;
46	    entityQueue.push(entity);
47	    processedEntities.clear();
48	
49	    // Destroyed entities may be the target or source of relations.
50	    // To avoid stale references, all these relations must be removed.
51	    // autoDestroy controls cascade behavior:
52	    // - 'source' (or 'orphan'): when target dies, destroy sources (e.g., parent dies → children die)
53	    // - 'target': when source dies, destroy targets (e.g., container dies → items die)
54	    while (entityQueue.length > 0) {
55	        const currentEntity = entityQueue.pop()!;
56	        if (processedEntities.has(currentEntity)) continue;
57	
58	        processedEntities.add(currentEntity);
59	
60	        for (const relation of ctx.relations) {
61	            const relationCtx = relation[$internal];
62	
63	            // Handle entities that have relations pointing TO currentEntity (currentEntity is target)
64	            // If autoDestroy is 'orphan', destroy those sources
65	            const sources = getEntitiesWithRelationTo(world, relation, currentEntity);
66	            for (const source of sources) {
67	                if (!world.has(source)) continue;
68	
69	                // Remove the relation from source to currentEntity
70	                cleanupRelationTarget(world, relation, source, currentEntity);
71	
72	                // If autoDestroy: 'source', queue the source for destruction
73	                if (relationCtx.autoDestroy === 'source') entityQueue.push(source);
74	            }
75	
76	            // Handle relations where currentEntity is the source pointing to targets
77	            // If autoDestroy is 'target', destroy those targets
78	            if (relationCtx.autoDestroy === 'target') {
79	                const targets = getRelationTargets(world, relation, currentEntity);
80	                for (const target of targets) {
81	                    if (!world.has(target)) continue;
82	                    if (!processedEntities.has(target)) entityQueue.push(target);
83	                }
84	            }
85	        }
86	
87	        // Remove all traits of the current entity.
88	        const entityTraits = ctx.entityTraits.get(currentEntity);
89	        if (entityTraits) {
90	            for (const trait of entityTraits) {
91	                removeTrait(world, currentEntity, trait);
92	            }
93	        }
94	
95	        // Free the entity.
96	        releaseEntity(ctx.entityIndex, currentEntity);
97	
98	        // Remove the entity from the all query.
99	        const allQuery = ctx.queriesHashMap.get('');
100	        if (allQuery) allQuery.remove(world, currentEntity);
101	
102	        // Remove all entity state from world.
103	        ctx.entityTraits.delete(currentEntity);
104	
105	        // Clear entity bitmasks.
106	        const eid = getEntityId(currentEntity);
107	        for (let i = 0; i < ctx.entityMasks.length; i++) {
108	            ctx.entityMasks[i][eid] = 0;
109	        }
110	    }
111	}
