53	function createTrait<S extends Schema>(schema: S = tagSchema as S): Trait<Norm<S>> {
54	    const isAoS = typeof schema === 'function';
55	    const isTag = !isAoS && Object.keys(schema).length === 0;
56	    const traitType: StoreType = isAoS ? 'aos' : isTag ? 'tag' : 'soa';
57	
58	    validateSchema(schema);
59	
60	    const id = traitId++;
61	    const Trait = Object.assign((params: TraitValue<Norm<S>>) => [Trait, params], {
62	        [$internal]: {
63	            id: id,
64	            set: createSetFunction[traitType](schema),
65	            fastSet: createFastSetFunction[traitType](schema),
66	            fastSetWithChangeDetection: createFastSetChangeFunction[traitType](schema),
67	            get: createGetFunction[traitType](schema),
68	            createStore: () => createStore<S>(schema),
69	            relation: null,
70	            type: traitType,
71	        },
72	    }) as Trait<Norm<S>>;
73	
74	    // Add public read-only properties
75	    Object.defineProperty(Trait, 'id', {
76	        value: id,
77	        writable: false,
78	        enumerable: true,
79	        configurable: false,
80	    });
81	
82	    Object.defineProperty(Trait, 'schema', {
83	        value: schema,
84	        writable: false,
85	        enumerable: true,
86	        configurable: false,
87	    });
88	
89	    return Trait;
