397	export function overlayGetTrait(world: World, entity: Entity, trait: Trait): unknown {
398	    const overlay = getEntityOverlay(world, entity);
399	    if (!overlay) return undefined;
400	    if (overlay.nullified || overlay.destroyed) return undefined;
401	
402	    const op = overlay.traitOps.get(trait);
403	    if (op) {
404	        if (op.op === 'remove') return undefined;
405	
406	        // If the entity already really has this trait, a deferred `add` is a
407	        // no-op (mirrors immediate add semantics), so the real value stands.
408	        if (!overlay.spawned && hasTrait(world, entity, trait)) {
409	            return getTrait(world, entity, trait);
410	        }
411	
412	        const traitCtx = trait[$internal];
